import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function UploadPage() {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [videoFile, setVideoFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    const token = localStorage.getItem('access');
    
    if (!token) {
      navigate('/login');
      return;
    }

    if (!videoFile) {
      setError('Выберите видеофайл');
      return;
    }

    const formData = new FormData();
    formData.append('title', title);
    formData.append('description', description);
    formData.append('video_file', videoFile);

    setUploading(true);
    setError('');
    
    try {
      await axios.post('http://localhost:8000/api/videos/', formData, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'multipart/form-data'
        }
      });
      navigate('/');
    } catch (error) {
      console.error('Ошибка загрузки:', error);
      setError('Ошибка при загрузке видео');
    } finally {
      setUploading(false);
    }
  };

  return (
    <div style={{ maxWidth: 600, margin: '0 auto' }}>
      <div className="card" style={{ padding: 32 }}>
        <h2 style={{ fontSize: 24, marginBottom: 24 }}>Загрузить видео</h2>
        
        {error && (
          <div style={{
            backgroundColor: '#fee2e2',
            color: 'var(--error)',
            padding: 12,
            borderRadius: 'var(--radius-md)',
            marginBottom: 20,
            fontSize: 14
          }}>
            {error}
          </div>
        )}
        
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label className="form-label">Название видео</label>
            <input
              type="text"
              className="form-input"
              placeholder="Введите название"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              required
            />
          </div>
          
          <div className="form-group">
            <label className="form-label">Описание</label>
            <textarea
              className="form-textarea"
              rows={4}
              placeholder="Расскажите о видео..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            />
            <span className="form-hint">Необязательное поле</span>
          </div>
          
          <div className="form-group">
            <label className="form-label">Видеофайл</label>
            <input
              type="file"
              accept="video/*"
              onChange={(e) => setVideoFile(e.target.files[0])}
              required
              style={{
                width: '100%',
                padding: '10px 0',
                border: '1px solid var(--border-light)',
                borderRadius: 'var(--radius-md)'
              }}
            />
            <span className="form-hint">Поддерживаются MP4, MOV, AVI</span>
          </div>
          
          <button
            type="submit"
            className="btn btn-primary"
            disabled={uploading}
            style={{ width: '100%' }}
          >
            {uploading ? 'Загрузка...' : '📤 Загрузить видео'}
          </button>
        </form>
      </div>
    </div>
  );
}

export default UploadPage;
